function Profile() {
  return (
    <div>
      <h2>Update Profile</h2>

      <input placeholder="Age" />
      <br />
      <input placeholder="Sex" />
      <br />
      <input placeholder="Height (cm)" />
      <br />
      <input placeholder="Weight (kg)" />
      <br />

      <button>Save Profile</button>
    </div>
  );
}

export default Profile;
